udt:













































.market-header {
    auto-size: grow fit;
    gap: 12;
    padding: 4 0;
}

.market-item-icon {
    size: 48 48;
    border-radius: 6;
    anchor: middle-center;
}

.market-header-info {
    auto-size: grow fit;
    flow: vertical;
    gap: 2;
    anchor: middle-left;
}

.market-price-summary {
    auto-size: grow fit;
    gap: 4;
    padding: 8 0;
}

.price-cell {
    auto-size: grow fit;
    flow: vertical;
    gap: 2;
    background-color: 0x15FFFFFF;
    border-radius: 6;
    padding: 8;
    anchor: top-center;
}

.price-label {
    font-size: 10;
    auto-size: grow fit;
}

.price-value {
    font-size: 16;
    auto-size: grow fit;
}

.market-listings {
    auto-size: grow fit;
    flow: vertical;
    gap: 2;
    overflow: scroll;
    max-size: 0 200;
}

.market-ingredients {
    auto-size: grow fit;
    flow: vertical;
    gap: 2;
    overflow: scroll;
}

.market-empty {
    auto-size: grow;
    flow: vertical;
    gap: 12;
    anchor: middle-center;
    padding: 40 0;
}
